import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({ id: null, nombre: "" });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({ ...categoriaActual, [e.target.name]: e.target.value });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (categoria) => {
    setCategoriaActual(categoria);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.id}`,
          categoriaActual
        );
      } else {
        await axios.post("http://localhost:5000/api/categorias", categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
        if (categoriaActual.id === id) setCategoriaActual({ id: null, nombre: "" });
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  return (
    <div className="container mt-5">
      {/* HEADER: Título y Nuevo */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold">Categorías</h2>
        <button className="btn btn-success" onClick={abrirModalAgregar}>
          ➕ Nueva Categoría
        </button>
      </div>

      {/* LISTA DE CATEGORÍAS */}
      <div className="row g-3">
        {categorias.map((cat) => (
          <div key={cat.id} className="col-md-4">
            <div
              className={`card shadow-sm p-3 ${
                categoriaActual.id === cat.id ? "border-primary" : ""
              }`}
            >
              <div className="d-flex justify-content-between align-items-center">
                <h5 className="card-title mb-0">{cat.nombre}</h5>
                <div>
                  {/* Botón Editar */}
                  <button
                    className="btn btn-warning btn-sm me-1"
                    onClick={() => abrirModalEditar(cat)}
                  >
                    ✏️
                  </button>

                  {/* Botón Eliminar */}
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => eliminarCategoria(cat.id)}
                  >
                    🗑️
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL PARA AGREGAR/EDITAR CATEGORÍA */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Editar Categoría" : "Agregar Categoría"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <div className="modal-body">
                <form onSubmit={guardarCategoria}>
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      name="nombre"
                      value={categoriaActual.nombre}
                      onChange={handleChange}
                      className="form-control"
                      required
                    />
                  </div>
                  <div className="text-end">
                    <button
                      type="button"
                      className="btn btn-secondary me-2"
                      onClick={() => setShowModal(false)}
                    >
                      Cancelar
                    </button>
                    <button type="submit" className="btn btn-primary">
                      {modoEdicion ? "Guardar Cambios" : "Agregar"}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
